using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Services ----------------------------------------------------------------

var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var provider = services.BuildServiceProvider();
var chatClient = provider.GetRequiredService<IChatClient>();
var loggerFactory = provider.GetRequiredService<ILoggerFactory>();

// --- Tools -------------------------------------------------------------------

var notebook = new ResearchNotebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(notebook.SearchWeb,
        nameof(notebook.SearchWeb),
        "Searches the web for a query and returns relevant results. " +
        "Use this to find information about a research topic."),

    AIFunctionFactory.Create(notebook.SaveNote,
        nameof(notebook.SaveNote),
        "Saves a research note with a title and content. " +
        "Use this to record important findings from your research."),

    AIFunctionFactory.Create(notebook.GetNotes,
        nameof(notebook.GetNotes),
        "Returns all saved research notes. " +
        "Use this to review what you have collected so far."),
};

// --- Agent -------------------------------------------------------------------

const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic the user
    gives you by using the tools available:

    1. Use SearchWeb to find information from multiple angles (definitions,
       recent developments, key people, pros/cons, etc.).
    2. Use SaveNote to record each important finding with a descriptive title.
    3. Perform at least 3 distinct searches to cover the topic well.
    4. After gathering enough notes, use GetNotes to review everything, then
       provide a well-structured summary with sections and key takeaways.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools,
    loggerFactory: loggerFactory,
    serviceProvider: provider);

// --- Run ---------------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔍  Research Agent                ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");

while (true)
{
    Console.Write("\n> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\nResearching: {topic}\n");

    notebook.Clear();

    try
    {
        var session = await agent.CreateSessionAsync();

        await foreach (var update in agent.RunStreamingAsync(
            $"Research this topic thoroughly: {topic}",
            session))
        {
            Console.Write(update.Text);
        }

        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\n⚠ Error: {ex.Message}");
    }
}

Console.WriteLine("\nGoodbye!");

// =============================================================================
//  Research tools
// =============================================================================

/// <summary>
/// Provides web search and note-taking capabilities for the research agent.
/// </summary>
sealed class ResearchNotebook
{
    private readonly List<(string Title, string Content)> _notes = [];
    private readonly HttpClient _http = new();

    [Description("Searches the web for information about a query.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            // Use the DuckDuckGo instant-answer API (no key required).
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await _http.GetStringAsync(url);

            var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;
            var sb = new StringBuilder();

            // Abstract / main answer
            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                sb.AppendLine($"Summary: {abstractText}");
                var source = root.GetProperty("AbstractSource").GetString();
                sb.AppendLine($"Source: {source}");
            }

            // Related topics (top 5)
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                var count = 0;
                foreach (var topic in topics.EnumerateArray())
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        !string.IsNullOrWhiteSpace(text.GetString()))
                    {
                        sb.AppendLine($"- {text.GetString()}");
                        if (++count >= 5) break;
                    }
                }
            }

            return sb.Length > 0
                ? sb.ToString()
                : $"No detailed results found for \"{query}\". Try rephrasing.";
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.Message}). Try a different query.";
        }
    }

    [Description("Saves a research note.")]
    public string SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The note content to save")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note \"{title}\" saved ({_notes.Count} total).";
    }

    [Description("Returns all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0) return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        Console.WriteLine($"  📋 Returning {_notes.Count} note(s)");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

